var e=JSON.parse(`[{"id":"L4_1","type":"dialog","speaker":"SOLDIER_GRONIA_NULL_F","text":{"KOREA":"국장님들께 보고드려! 어서!","JPN":"局長に報告しろ！　早く！","ENG":"Inform the Chiefs! Now!","TWN":"快報告部長！快！！"},"stage":{"bg":"GRONIA_STREET","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SOLDIER_GRONIA_NULL_A","face":"UNIT_IDLE"},"C":{"char_id":"SOLDIER_GRONIA_NULL_F","face":"UNIT_IDLE"},"R":{"char_id":"SOLDIER_GRONIA_NULL_B","face":"UNIT_IDLE"}}}},{"id":"L5_1","type":"dialog","speaker":"SOLDIER_GRONIA_NULL_A","text":{"KOREA":"어떻게 된 거야! 전차포를 몇 발이나 맞아도 멀쩡하잖아?!","JPN":"どういうことだ！　戦車砲を何発くらってもビクともしないなんて！？","ENG":"How can that be? How many times can it get hit by a tank and still be completely unscathed?!","TWN":"怎麼會這樣！被坦克砲打中那麼多次卻毫髮無傷？！"},"stage":{"bg":"GRONIA_STREET","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SOLDIER_GRONIA_NULL_A","face":"UNIT_IDLE"},"C":{"char_id":"SOLDIER_GRONIA_NULL_F","face":"UNIT_IDLE"},"R":{"char_id":"SOLDIER_GRONIA_NULL_B","face":"UNIT_IDLE"}}}},{"id":"L6_1","type":"dialog","speaker":"SOLDIER_GRONIA_NULL_B","text":{"KOREA":"이, 이쪽으로 온다!!","JPN":"こ、こっちに来る！！","ENG":"I-It’s coming this way!!","TWN":"她…她過來了！！"},"stage":{"bg":"GRONIA_STREET","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SOLDIER_GRONIA_NULL_A","face":"UNIT_IDLE"},"C":{"char_id":"SOLDIER_GRONIA_NULL_F","face":"UNIT_IDLE"},"R":{"char_id":"SOLDIER_GRONIA_NULL_B","face":"UNIT_IDLE"}}}},{"id":"L11_1","type":"dialog","speaker":"MORS_SHADOW_ARMOR_NULL","text":{"KOREA":"……마에스트로가, 여기 있다고 들었다.","JPN":"……マエストロが、ここにいると聞いた。","ENG":"...Maestra, is said to be here.","TWN":"……聽說指揮家在這裡。"},"stage":{"bg":"GRONIA_STREET","bgm":"THEMA_SHADOW_PALACE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORS_SHADOW_ARMOR_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"MORS_SHADOW_ARMOR_NULL","text":{"KOREA":"여인을 내놓아라. 그리하면 그대들의 터전에서 물러날지니.","JPN":"女をよこせ。そうすればそなたらの地から立ち去ろう。","ENG":"Give the woman to me. Do so, and I shall withdraw from this base.","TWN":"把那女人交出來，那我就離開這裡。"},"stage":{"bg":"GRONIA_STREET","bgm":"THEMA_SHADOW_PALACE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORS_SHADOW_ARMOR_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"SOLDIER_GRONIA_NULL_C","text":{"KOREA":"도심에서 벌어진 난동의 주범이다! 쏴!!","JPN":"都心で起こった騒ぎの主犯だ！　撃て！！","ENG":"That’s the one behind the rampage in the city! Fire!!","TWN":"她就是市中心混戰的主嫌！開槍！！"},"stage":{"bg":"GRONIA_STREET","bgm":"THEMA_SHADOW_PALACE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORS_SHADOW_ARMOR_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"SOLDIER_GRONIA_NULL_D","text":{"KOREA":"젠장! 여기가 어딘 줄 알고!!","JPN":"クソ！　ここをどこだと思ってんだ！！","ENG":"Damn it! Where do you think you’re standing?","TWN":"可惡！竟敢在我們的地盤造次！！"},"stage":{"bg":"GRONIA_STREET","bgm":"THEMA_SHADOW_PALACE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORS_SHADOW_ARMOR_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"ROOKIE_GRONIA_NULL_NULL","text":{"KOREA":"저 건물 파괴범이 왜 여기에……?","JPN":"あの建物を破壊した犯人がなんでここに……？","ENG":"The one that destroyed all those buildings... Why is she here...?","TWN":"那個破壞建築物的犯人怎麼會出現在……？"},"stage":{"bg":"GRONIA_STREET","bgm":"THEMA_SHADOW_PALACE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"BASS_HARMONY_NULL_HIDE","text":{"KOREA":"모르스…….","JPN":"モールス……","ENG":"Mors...","TWN":"莫爾斯……"},"stage":{"bg":"GRONIA_STREET","bgm":"THEMA_SHADOW_PALACE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BASS_HARMONY_NULL_HIDE","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"BASS_HARMONY_NULL_HIDE","text":{"KOREA":"중사님, 가자. 지금이 바로 기회야.","JPN":"軍曹さん、行こう。今がチャンスよ。","ENG":"Let’s go, Sergeant. Now’s our chance.","TWN":"中士，走吧！趁現在！"},"stage":{"bg":"GRONIA_STREET","bgm":"THEMA_SHADOW_PALACE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"BASS_HARMONY_NULL_HIDE","face":"UNIT_SERIOUS"}}}},{"id":"L23_1","type":"dialog","speaker":"ROOKIE_GRONIA_NULL_NULL","text":{"KOREA":"뭐라굽쇼?","JPN":"はあ？","ENG":"What did you say?","TWN":"什麼意思？"},"stage":{"bg":"GRONIA_STREET","bgm":"THEMA_SHADOW_PALACE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"BASS_HARMONY_NULL_HIDE","face":"UNIT_SERIOUS"}}}},{"id":"L24_1","type":"dialog","speaker":"BASS_HARMONY_NULL_HIDE","text":{"KOREA":"저 사람이 왜 나타났는지 몰라도 보안국 사람들 시선이 전부 저기에 쏠려 있잖아.","JPN":"あの人がなんで現れたかは知らないけど、保安局みんなの視線があっちを向いてるじゃない。","ENG":"I don’t know why that person appeared, but all of the National Security’s eyes are on it.","TWN":"雖然不清楚她為何會出現在這裡，但現在安全局的人全都忙於應付她，"},"stage":{"bg":"GRONIA_STREET","bgm":"THEMA_SHADOW_PALACE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"BASS_HARMONY_NULL_HIDE","face":"UNIT_IDLE"}}}},{"id":"L25_1","type":"dialog","speaker":"BASS_HARMONY_NULL_HIDE","text":{"KOREA":"지금이라면 레아를 구할 수 있을 거야.","JPN":"今ならレアを助けられるはずよ。","ENG":"If we go now, we can save Leah.","TWN":"現在就是救出蕾亞的好機會！"},"stage":{"bg":"GRONIA_STREET","bgm":"THEMA_SHADOW_PALACE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"BASS_HARMONY_NULL_HIDE","face":"UNIT_IDLE"}}}},{"id":"L26_1","type":"dialog","speaker":"ROOKIE_GRONIA_NULL_NULL","text":{"KOREA":"우리 좀 상식적인 논의를 해 봐요. 아무리 난리가 났어도 안에 경비 한 명 없겠어요?","JPN":"ちょっと常識的に話してみましょうよ。いくら騒ぎになったとしても、中に警備員一人くらいは残ってると思いません？","ENG":"Whoa, there. Let’s have a common sense talk. No matter how crazy things are outside, they’ll always have a security guard inside, won’t they?","TWN":"我們來理性溝通一下，就算場面再怎麼混亂，但你覺得裡面有可能會沒人看守嗎？"},"stage":{"bg":"GRONIA_STREET","bgm":"THEMA_SHADOW_PALACE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"BASS_HARMONY_NULL_HIDE","face":"UNIT_IDLE"}}}},{"id":"L28_1","type":"dialog","speaker":"BASS_HARMONY_NULL_HIDE","text":{"KOREA":"레아는 내게 소중한 존재야. 중사님이 싫다면 언니 혼자라도 갈래.","JPN":"私にとってレアは大事な存在なの。軍曹さんが嫌ならお姉ちゃん一人ででも行くよ。","ENG":"Leah is precious to me. If you don’t want to go, I will go alone.","TWN":"蕾亞對我而言很重要，中士你不願意的話，那姊姊我自己去。"},"stage":{"bg":"GRONIA_STREET","bgm":"THEMA_SHADOW_PALACE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"BASS_HARMONY_NULL_HIDE","face":"UNIT_DESPAIR"}}}},{"id":"L29_1","type":"dialog","speaker":"BASS_HARMONY_NULL_HIDE","text":{"KOREA":"중사님은 휘말리지 않게 안전한 곳으로 피해 있어.","JPN":"軍曹さんは巻き込まれないように安全なところに避難して。","ENG":"Sergeant, find somewhere safe where you won’t get caught up in all this.","TWN":"你就找個安全的地方躲好。"},"stage":{"bg":"GRONIA_STREET","bgm":"THEMA_SHADOW_PALACE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"BASS_HARMONY_NULL_HIDE","face":"UNIT_IDLE"}}}},{"id":"L32_1","type":"dialog","speaker":"ROOKIE_GRONIA_NULL_NULL","text":{"KOREA":"……뭐야, 저 <color=#ffd34c>어떻게든 되겠지</color> 같은 안일한 태도는?","JPN":"……何なの、あの<color=#ffd34c>どうにかなるだろう</color>みたいな気楽な態度。","ENG":"...What’s with that <color=#ffd34c>Everything will work out fine</color> carefree attitude?","TWN":"……什麼嘛，那種<color=#ffd34c>毅然決然</color>的態度是怎樣？"},"stage":{"bg":"GRONIA_STREET","bgm":"THEMA_SHADOW_PALACE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"ROOKIE_GRONIA_NULL_NULL","text":{"KOREA":"사람이 마음 먹어서 되는 건 오늘 할일을 내일의 나한테 떠넘기기밖에 없다고.","JPN":"人が決意してできるのは、今日の仕事を明日の私に押し付けるくらいしかないっての。","ENG":"The only thing people can do when they make up their minds is to hand over today's tasks to tomorrow's me.","TWN":"人唯一下定決心會做的事，就只有今日事明日畢啦！"},"stage":{"bg":"GRONIA_STREET","bgm":"THEMA_SHADOW_PALACE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"ROOKIE_GRONIA_NULL_NULL","text":{"KOREA":"아, 진짜 한 대 콱 쥐어박고 싶다!","JPN":"あ～、マジでガツンと一発殴りたい！","ENG":"Ugh, I really want to smack you for this!","TWN":"討厭，真想給她一拳！"},"stage":{"bg":"GRONIA_STREET","bgm":"THEMA_SHADOW_PALACE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_HATE"},"R":null}}}]`);export{e as default};